#include<bits/stdc++.h>
using namespace std;
int n,m,a[100010];
pair<int,int> q[1000010];
vector<int> v[1000010];
int s[100010];
int lowbit(int x)
{
    return x&-x;
}
void update(int x,int k)
{
    for(int i=x;i<=n;i+=lowbit(i))
    {
        s[i]+=k;
    }
}
int query(int x)
{
    int ans=0;
    for(int i=x;i;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
struct st
{
    int lg[100010];
    int f[100010][22],f1[100010][22];
    void init()
    {
        lg[1]=0;
        for(int i=2;i<=n;i++)
        {
            lg[i]=lg[i/2]+1;
        }
        for(int i=1;i<=n;i++)
        {
            f[i][0]=f1[i][0]=a[i];
        }
        for(int j=1;j<=lg[n];j++)
        {
            for(int i=1;i<=n-(1<<j)+1;i++)
            {
                f[i][j]=max(f[i][j-1],f[i+(1<<(j-1))][j-1]);
                f1[i][j]=min(f1[i][j-1],f1[i+(1<<(j-1))][j-1]);
            }
        }
    }
    int getmax(int l,int r)
    {
        int temp=lg[r-l+1];
        return max(f[l][temp],f[r-(1<<temp)+1][temp]);
    }
    int getmin(int l,int r)
    {
        int temp=lg[r-l+1];
        return min(f1[l][temp],f1[r-(1<<temp)+1][temp]);
    }
}t;
int main()
{
    scanf("%d%d",&n,&m);
    for(int i=1;i<=n;i++)
    {
        a[i]=m+1;
    }
    for(int i=1;i<=m;i++)
    {
        int op;
        scanf("%d",&op);
        q[i]={-1,-1};
        if(op==1)
        {
            int x;
            scanf("%d",&x);
            a[x]=min(a[x],i);
        }
        else
        {
            scanf("%d%d",&q[i].first,&q[i].second);
        }
    }
    t.init();
    for(int i=1;i<=n;i++)
    {
        update(i,1);
        int lst=0;
        for(int j=1;j<=n;j+=i)
        {
            int l=j,r=min(n,i+j-1);
            lst=max(lst,t.getmin(l,r));
            v[lst].push_back(i);
        }
    }
    for(int i=1;i<=m;i++)
    {
        for(int j:v[i])
        {
            update(j,1);
        }
        if(q[i].first!=-1)
        {
            printf("%d\n",query(q[i].second)-query(q[i].first-1));
        }
    }
    return 0;
}
